#!/usr/bin/env pwsh\n# LearnIQ Local Development Setup Script\n# Run: .\\setup-local.ps1\n\nWrite-Host \"🚀 LearnIQ Local Development Setup\" -ForegroundColor Cyan\nWrite-Host \"================================\" -ForegroundColor Cyan\nWrite-Host \"\"\n\n# Check Node.js\nWrite-Host \"Checking Node.js installation...\" -ForegroundColor Yellow\nif (-not (Get-Command node -ErrorAction SilentlyContinue)) {\n    Write-Host \"❌ Node.js not found. Please install Node.js first.\" -ForegroundColor Red\n    exit 1\n}\nnode --version\nWrite-Host \"✓ Node.js found\" -ForegroundColor Green\nWrite-Host \"\"\n\n# Check MySQL\nWrite-Host \"Checking MySQL installation...\" -ForegroundColor Yellow\nif (-not (Get-Command mysql -ErrorAction SilentlyContinue)) {\n    Write-Host \"⚠️  MySQL not found. Make sure MySQL is installed and in PATH.\" -ForegroundColor Yellow\n} else {\n    mysql --version\n    Write-Host \"✓ MySQL found\" -ForegroundColor Green\n}\nWrite-Host \"\"\n\n# Setup Frontend\nWrite-Host \"Setting up Frontend...\" -ForegroundColor Yellow\nif (-not (Test-Path \".env.local\")) {\n    Write-Host \"Creating .env.local...\" -ForegroundColor Gray\n    @\"\nVITE_API_URL=http://localhost:5000/api/v1\nREACT_APP_API_URL=http://localhost:5000/api/v1\nNODE_ENV=development\nVITE_DEBUG=true\nVITE_SERVICE_WORKER_ENABLED=true\nVITE_OFFLINE_MODE=true\n\"@ | Out-File -FilePath \".env.local\" -Encoding UTF8\n    Write-Host \"✓ .env.local created\" -ForegroundColor Green\n} else {\n    Write-Host \"✓ .env.local already exists\" -ForegroundColor Green\n}\n\nif (-not (Test-Path \"node_modules\")) {\n    Write-Host \"Installing frontend dependencies...\" -ForegroundColor Gray\n    npm install\n    Write-Host \"✓ Frontend dependencies installed\" -ForegroundColor Green\n} else {\n    Write-Host \"✓ Frontend dependencies already installed\" -ForegroundColor Green\n}\nWrite-Host \"\"\n\n# Setup Backend\nWrite-Host \"Setting up Backend...\" -ForegroundColor Yellow\nif (-not (Test-Path \"backend\\.env.local\")) {\n    Write-Host \"Creating backend/.env.local...\" -ForegroundColor Gray\n    @\"\nPORT=5000\nNODE_ENV=development\nDB_HOST=localhost\nDB_USER=root\nDB_PASSWORD=password\nDB_DATABASE=pwa_let_db\nDB_PORT=3306\nJWT_SECRET=your_super_secret_jwt_key_change_this_in_production\nCORS_ORIGIN=http://localhost:3000,http://localhost:5173,http://127.0.0.1:3000\nAPI_PREFIX=/api/v1\nFRONTEND_URL=http://localhost:3000\n\"@ | Out-File -FilePath \"backend\\.env.local\" -Encoding UTF8\n    Write-Host \"✓ backend/.env.local created\" -ForegroundColor Green\n} else {\n    Write-Host \"✓ backend/.env.local already exists\" -ForegroundColor Green\n}\n\nif (-not (Test-Path \"backend\\node_modules\")) {\n    Write-Host \"Installing backend dependencies...\" -ForegroundColor Gray\n    Push-Location backend\n    npm install\n    Pop-Location\n    Write-Host \"✓ Backend dependencies installed\" -ForegroundColor Green\n} else {\n    Write-Host \"✓ Backend dependencies already installed\" -ForegroundColor Green\n}\nWrite-Host \"\"\n\n# Database setup\nWrite-Host \"Database Setup\" -ForegroundColor Yellow\nWrite-Host \"Important: Make sure MySQL is running before continuing.\" -ForegroundColor Gray\nWrite-Host \"To run migrations and seed data, execute:\" -ForegroundColor Gray\nWrite-Host \"  cd backend\" -ForegroundColor Cyan\nWrite-Host \"  npm run migrate\" -ForegroundColor Cyan\nWrite-Host \"  npm run seed\" -ForegroundColor Cyan\nWrite-Host \"\"\n\n# Final instructions\nWrite-Host \"✅ Setup Complete!\" -ForegroundColor Green\nWrite-Host \"\"\nWrite-Host \"Next Steps:\" -ForegroundColor Cyan\nWrite-Host \"1. Update database credentials in backend/.env.local\" -ForegroundColor White\nWrite-Host \"2. Make sure MySQL is running\" -ForegroundColor White\nWrite-Host \"3. Run database migrations: cd backend && npm run migrate\" -ForegroundColor White\nWrite-Host \"4. Open two terminals and run:\" -ForegroundColor White\nWrite-Host \"   Terminal 1 (Frontend): npm run dev\" -ForegroundColor Cyan\nWrite-Host \"   Terminal 2 (Backend):  cd backend && npm run dev\" -ForegroundColor Cyan\nWrite-Host \"5. Open http://localhost:3000 in your browser\" -ForegroundColor White\nWrite-Host \"\"\nWrite-Host \"For more help, see DEPLOYMENT_GUIDE_COMPLETE.md\" -ForegroundColor Gray\n